//! Quantum Integrated Information Theory (IIT)
//!
//! Implements Integrated Information Theory (Tononi's Phi) for quantum systems.
//! IIT proposes that consciousness corresponds to integrated information --
//! information generated by a system above and beyond its parts.
//!
//! **World first**: No quantum simulator has built-in IIT consciousness metrics.
//!
//! Phi quantifies the minimum information lost when the system is partitioned
//! into its most independent parts (the Minimum Information Partition, or MIP).
//! A system with high Phi is more than the sum of its parts -- the hallmark
//! of integrated information and, according to IIT, of consciousness.
//!
//! This module provides three formulations:
//!
//! - **Phi 2.0**: Original IIT using Earth Mover's Distance on transition
//!   probability matrices (Tononi 2004).
//! - **Phi 3.0**: Minimum Information Partition formulation using cause-effect
//!   repertoires (Oizumi, Albantakis, Tononi 2014).
//! - **Phi Star (Phi*)**: Practical approximation via quantum mutual information,
//!   much faster than exact Phi 3.0.
//!
//! Additionally, a purely quantum-native geometric Phi is provided, computed
//! directly from the von Neumann entropy of reduced density matrices.
//!
//! # Example
//!
//! ```rust
//! use nqpu_metal::quantum_iit::{QuantumIIT, IITConfig, PhiVersion};
//! use nqpu_metal::{QuantumState, GateOperations};
//!
//! let config = IITConfig::default();
//! let iit = QuantumIIT::new(config);
//!
//! // Create a Bell state (maximally entangled)
//! let mut state = QuantumState::new(2);
//! GateOperations::h(&mut state, 0);
//! GateOperations::cnot(&mut state, 0, 1);
//!
//! let result = iit.compute_phi(&state);
//! assert!(result.phi > 0.0, "Entangled states have positive Phi");
//! ```

use crate::{C64, QuantumState};
use std::fmt;

// ============================================================
// CONSTANTS
// ============================================================

/// Default convergence precision for eigenvalue computation.
const DEFAULT_PRECISION: f64 = 1e-8;

/// Maximum number of Jacobi sweeps for Hermitian eigensolvers.
const MAX_JACOBI_SWEEPS: usize = 200;

/// Threshold below which eigenvalues are treated as zero in entropy calculations.
const ENTROPY_EPSILON: f64 = 1e-15;

// ============================================================
// ERROR TYPES
// ============================================================

/// Errors that can occur during IIT computation.
#[derive(Clone, Debug, PartialEq)]
pub enum IITError {
    /// The requested partition is invalid for the given system size.
    InvalidPartition(String),
    /// Matrix dimensions do not match the expected system size.
    DimensionMismatch {
        expected: usize,
        got: usize,
    },
    /// The transition probability matrix is singular or degenerate.
    SingularTPM(String),
    /// Phi computation failed due to numerical or logical issues.
    PhiComputationFailed(String),
}

impl fmt::Display for IITError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            IITError::InvalidPartition(msg) => write!(f, "Invalid partition: {}", msg),
            IITError::DimensionMismatch { expected, got } => {
                write!(f, "Dimension mismatch: expected {}, got {}", expected, got)
            }
            IITError::SingularTPM(msg) => write!(f, "Singular TPM: {}", msg),
            IITError::PhiComputationFailed(msg) => {
                write!(f, "Phi computation failed: {}", msg)
            }
        }
    }
}

impl std::error::Error for IITError {}

// ============================================================
// ENUMS
// ============================================================

/// IIT formulation version.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum PhiVersion {
    /// IIT 2.0: original formulation using Earth Mover's Distance on TPMs.
    Phi2_0,
    /// IIT 3.0: Minimum Information Partition with cause-effect repertoires.
    Phi3_0,
    /// Practical approximation using quantum mutual information. Much faster.
    PhiStar,
}

/// Strategy for searching over partitions to find the MIP.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum PartitionStrategy {
    /// Try all bipartitions and find the MIP. Complexity O(2^(n-1)).
    BipartitionSearch,
    /// Try all possible partitions (very expensive, combinatorial explosion).
    Exhaustive,
    /// Partition into individual elements (each qubit is its own part).
    AtomicPartition,
    /// Greedy search for approximate MIP (fast but not guaranteed optimal).
    Greedy,
}

// ============================================================
// CONFIGURATION
// ============================================================

/// Configuration for IIT analysis.
///
/// Use `IITConfig::default()` for sensible defaults, or construct manually
/// for fine-grained control over the computation.
#[derive(Clone, Debug)]
pub struct IITConfig {
    /// Number of qubits in the system.
    pub num_qubits: usize,
    /// Which IIT formulation to use.
    pub phi_version: PhiVersion,
    /// Strategy for searching partitions.
    pub partition_strategy: PartitionStrategy,
    /// Numerical precision for convergence tests.
    pub precision: f64,
}

impl Default for IITConfig {
    fn default() -> Self {
        IITConfig {
            num_qubits: 4,
            phi_version: PhiVersion::Phi3_0,
            partition_strategy: PartitionStrategy::BipartitionSearch,
            precision: DEFAULT_PRECISION,
        }
    }
}

impl IITConfig {
    /// Create a new configuration with explicit qubit count.
    pub fn new(num_qubits: usize) -> Self {
        IITConfig {
            num_qubits,
            ..Default::default()
        }
    }

    /// Set the Phi version.
    pub fn with_phi_version(mut self, version: PhiVersion) -> Self {
        self.phi_version = version;
        self
    }

    /// Set the partition search strategy.
    pub fn with_partition_strategy(mut self, strategy: PartitionStrategy) -> Self {
        self.partition_strategy = strategy;
        self
    }

    /// Set the numerical precision.
    pub fn with_precision(mut self, precision: f64) -> Self {
        self.precision = precision;
        self
    }
}

// ============================================================
// PARTITION
// ============================================================

/// A partition of qubit indices into disjoint subsets.
#[derive(Clone, Debug, PartialEq)]
pub struct Partition {
    /// Each element is a set of qubit indices forming one part.
    pub parts: Vec<Vec<usize>>,
}

impl Partition {
    /// Create a bipartition from a bitmask. Bit i set means qubit i is in part A.
    pub fn from_bitmask(n: usize, mask: usize) -> Self {
        let mut part_a = Vec::new();
        let mut part_b = Vec::new();
        for i in 0..n {
            if (mask >> i) & 1 == 1 {
                part_a.push(i);
            } else {
                part_b.push(i);
            }
        }
        Partition {
            parts: vec![part_a, part_b],
        }
    }

    /// Create an atomic partition (each qubit is its own part).
    pub fn atomic(n: usize) -> Self {
        let parts: Vec<Vec<usize>> = (0..n).map(|i| vec![i]).collect();
        Partition { parts }
    }

    /// Check that the partition covers all qubits exactly once.
    pub fn is_valid(&self, n: usize) -> bool {
        let mut seen = vec![false; n];
        for part in &self.parts {
            for &q in part {
                if q >= n || seen[q] {
                    return false;
                }
                seen[q] = true;
            }
        }
        seen.iter().all(|&s| s)
    }

    /// Total number of qubits across all parts.
    pub fn total_qubits(&self) -> usize {
        self.parts.iter().map(|p| p.len()).sum()
    }
}

impl fmt::Display for Partition {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        let strs: Vec<String> = self
            .parts
            .iter()
            .map(|p| format!("{{{}}}", p.iter().map(|q| q.to_string()).collect::<Vec<_>>().join(",")))
            .collect();
        write!(f, "{}", strs.join(" | "))
    }
}

// ============================================================
// TRANSITION PROBABILITY MATRIX
// ============================================================

/// Transition Probability Matrix (TPM) for a quantum system.
///
/// TPM[i][j] = P(state j at t+1 | state i at t).
/// Each row is a probability distribution and must sum to 1.
#[derive(Clone, Debug)]
pub struct TransitionProbabilityMatrix {
    /// The matrix stored as `matrix[i][j]`.
    pub matrix: Vec<Vec<f64>>,
}

impl TransitionProbabilityMatrix {
    /// Construct a TPM from a unitary matrix with optional depolarizing noise.
    ///
    /// From unitary U, TPM[i][j] = |U[j][i]|^2 (transition probability from
    /// computational basis state i to state j). With noise parameter p,
    /// the TPM is mixed with the uniform distribution:
    /// TPM = (1-p) * TPM_unitary + p/D * ones
    pub fn from_unitary(unitary: &[Vec<C64>], noise: f64) -> Self {
        let d = unitary.len();
        let mut matrix = vec![vec![0.0; d]; d];

        for i in 0..d {
            for j in 0..d {
                // TPM[i][j] = |U[j][i]|^2 = |<j|U|i>|^2
                matrix[i][j] = unitary[j][i].norm_sqr();
            }
        }

        // Apply depolarizing noise
        if noise > 0.0 {
            let uniform = 1.0 / d as f64;
            for row in matrix.iter_mut() {
                for elem in row.iter_mut() {
                    *elem = (1.0 - noise) * *elem + noise * uniform;
                }
            }
        }

        TransitionProbabilityMatrix { matrix }
    }

    /// Construct a TPM from a quantum channel given as Kraus operators.
    ///
    /// Each Kraus operator is a dim x dim matrix stored as Vec<Vec<C64>>.
    /// TPM[i][j] = sum_k |<j| K_k |i>|^2
    pub fn from_quantum_channel(channel: &[Vec<Vec<C64>>]) -> Self {
        if channel.is_empty() {
            return TransitionProbabilityMatrix {
                matrix: Vec::new(),
            };
        }
        let d = channel[0].len();
        let mut matrix = vec![vec![0.0; d]; d];

        for kraus in channel {
            for i in 0..d {
                for j in 0..d {
                    // <j| K |i> = K[j][i]
                    matrix[i][j] += kraus[j][i].norm_sqr();
                }
            }
        }

        TransitionProbabilityMatrix { matrix }
    }

    /// Dimension of the TPM (number of basis states).
    pub fn dim(&self) -> usize {
        self.matrix.len()
    }

    /// Check that every row sums to 1 (within tolerance).
    pub fn is_stochastic(&self, tol: f64) -> bool {
        for row in &self.matrix {
            let sum: f64 = row.iter().sum();
            if (sum - 1.0).abs() > tol {
                return false;
            }
        }
        true
    }

    /// Extract the sub-TPM for a subset of qubits by marginalizing over others.
    ///
    /// Given a set of qubit indices, produce a TPM acting only on those qubits
    /// by summing over all configurations of the remaining qubits.
    pub fn marginal_tpm(&self, qubits: &[usize], total_qubits: usize) -> TransitionProbabilityMatrix {
        let n_sub = qubits.len();
        let d_sub = 1 << n_sub;
        let d_full = 1 << total_qubits;
        let other_qubits: Vec<usize> = (0..total_qubits)
            .filter(|q| !qubits.contains(q))
            .collect();
        let n_other = other_qubits.len();
        let d_other = 1 << n_other;

        let mut sub_matrix = vec![vec![0.0; d_sub]; d_sub];

        // For each sub-state pair (i_sub, j_sub), sum over all other-qubit configs
        for i_sub in 0..d_sub {
            for j_sub in 0..d_sub {
                let mut total = 0.0;
                for i_other in 0..d_other {
                    let i_full = Self::compose_index(i_sub, qubits, i_other, &other_qubits, total_qubits);
                    for j_other in 0..d_other {
                        let j_full = Self::compose_index(j_sub, qubits, j_other, &other_qubits, total_qubits);
                        if i_full < d_full && j_full < d_full {
                            total += self.matrix[i_full][j_full];
                        }
                    }
                }
                sub_matrix[i_sub][j_sub] = total;
            }
        }

        // Normalize rows
        for row in sub_matrix.iter_mut() {
            let sum: f64 = row.iter().sum();
            if sum > 0.0 {
                for elem in row.iter_mut() {
                    *elem /= sum;
                }
            }
        }

        TransitionProbabilityMatrix { matrix: sub_matrix }
    }

    /// Compose a full index from sub-system and other-system indices.
    fn compose_index(
        sub_val: usize,
        sub_qubits: &[usize],
        other_val: usize,
        other_qubits: &[usize],
        _total_qubits: usize,
    ) -> usize {
        let mut full_idx = 0usize;
        for (bit_pos, &qubit) in sub_qubits.iter().enumerate() {
            if (sub_val >> bit_pos) & 1 == 1 {
                full_idx |= 1 << qubit;
            }
        }
        for (bit_pos, &qubit) in other_qubits.iter().enumerate() {
            if (other_val >> bit_pos) & 1 == 1 {
                full_idx |= 1 << qubit;
            }
        }
        full_idx
    }

    /// Compute the tensor product of two TPMs.
    pub fn tensor_product(a: &TransitionProbabilityMatrix, b: &TransitionProbabilityMatrix) -> TransitionProbabilityMatrix {
        let da = a.dim();
        let db = b.dim();
        let d = da * db;
        let mut matrix = vec![vec![0.0; d]; d];

        for ia in 0..da {
            for ja in 0..da {
                for ib in 0..db {
                    for jb in 0..db {
                        matrix[ia * db + ib][ja * db + jb] = a.matrix[ia][ja] * b.matrix[ib][jb];
                    }
                }
            }
        }

        TransitionProbabilityMatrix { matrix }
    }
}

