    // ----------------------------------------------------------
    // 10. Mutual information > 0 for Bell state
    // ----------------------------------------------------------
    #[test]
    fn test_mutual_information_bell() {
        let state = bell_state();
        let config = IITConfig::new(2);
        let iit = QuantumIIT::new(config);
        let partition = Partition::from_bitmask(2, 1); // {0} | {1}

        let mi = iit.mutual_information(&state, &partition);
        assert!(
            mi > 0.5,
            "Bell state should have significant MI, got {}",
            mi
        );
        // For Bell state, MI should be approximately 2 * ln(2)
        let expected = 2.0 * 2.0_f64.ln();
        assert!(
            (mi - expected).abs() < 0.2,
            "Bell state MI should be close to 2*ln(2) = {:.4}, got {:.4}",
            expected,
            mi
        );
    }

    // ----------------------------------------------------------
    // 11. Partial trace preserves trace
    // ----------------------------------------------------------
    #[test]
    fn test_partial_trace() {
        let state = bell_state();
        let amps = state.amplitudes_ref();
        let rho = density_matrix_from_state(amps);
        let n = 2;
        let d = 4;

        // Full trace should be 1
        let tr_full = matrix_trace(&rho, d);
        assert!(
            (tr_full.re - 1.0).abs() < 1e-10,
            "Full density matrix trace should be 1, got {}",
            tr_full.re
        );

        // Partial trace over qubit 1 (keep qubit 0)
        let rho_0 = partial_trace(&rho, n, &[0]);
        let tr_0 = matrix_trace(&rho_0, 2);
        assert!(
            (tr_0.re - 1.0).abs() < 1e-10,
            "Reduced density matrix trace should be 1, got {}",
            tr_0.re
        );

        // Partial trace over qubit 0 (keep qubit 1)
        let rho_1 = partial_trace(&rho, n, &[1]);
        let tr_1 = matrix_trace(&rho_1, 2);
        assert!(
            (tr_1.re - 1.0).abs() < 1e-10,
            "Reduced density matrix trace should be 1, got {}",
            tr_1.re
        );

        // For Bell state, reduced state should be maximally mixed: rho = I/2
        assert!(
            (rho_0[0].re - 0.5).abs() < 1e-10,
            "Bell state reduced rho[0][0] should be 0.5, got {}",
            rho_0[0].re
        );
        assert!(
            (rho_0[3].re - 0.5).abs() < 1e-10,
            "Bell state reduced rho[1][1] should be 0.5, got {}",
            rho_0[3].re
        );
    }

    // ----------------------------------------------------------
    // 12. Von Neumann entropy = 0 for pure state
    // ----------------------------------------------------------
    #[test]
    fn test_von_neumann_entropy_pure() {
        // |0> state: rho = |0><0|
        let rho = vec![
            C64::new(1.0, 0.0),
            C64::new(0.0, 0.0),
            C64::new(0.0, 0.0),
            C64::new(0.0, 0.0),
        ];
        let s = von_neumann_entropy(&rho, 2);
        assert!(
            s.abs() < 1e-8,
            "Pure state should have S = 0, got {}",
            s
        );

        // Bell state (global pure state)
        let state = bell_state();
        let amps = state.amplitudes_ref();
        let rho_bell = density_matrix_from_state(amps);
        let s_bell = von_neumann_entropy(&rho_bell, 4);
        assert!(
            s_bell.abs() < 1e-8,
            "Pure Bell state should have S = 0, got {}",
            s_bell
        );
    }

    // ----------------------------------------------------------
    // 13. Von Neumann entropy = ln(D) for maximally mixed
    // ----------------------------------------------------------
    #[test]
    fn test_von_neumann_entropy_maximally_mixed() {
        // Maximally mixed 2x2: rho = I/2
        let rho = vec![
            C64::new(0.5, 0.0),
            C64::new(0.0, 0.0),
            C64::new(0.0, 0.0),
            C64::new(0.5, 0.0),
        ];
        let s = von_neumann_entropy(&rho, 2);
        let expected = 2.0_f64.ln(); // ln(2)
        assert!(
            (s - expected).abs() < 1e-8,
            "Maximally mixed 2x2 should have S = ln(2) = {:.6}, got {:.6}",
            expected,
            s
        );

        // Maximally mixed 4x4: rho = I/4
        let mut rho4 = vec![C64::new(0.0, 0.0); 16];
        for i in 0..4 {
            rho4[i * 4 + i] = C64::new(0.25, 0.0);
        }
        let s4 = von_neumann_entropy(&rho4, 4);
        let expected4 = 4.0_f64.ln(); // ln(4) = 2*ln(2)
        assert!(
            (s4 - expected4).abs() < 1e-8,
            "Maximally mixed 4x4 should have S = ln(4) = {:.6}, got {:.6}",
            expected4,
            s4
        );
    }

    // ----------------------------------------------------------
    // 14. Phi* correlates with Phi 3.0
    // ----------------------------------------------------------
    #[test]
    fn test_phi_star_approximation() {
        let state = bell_state();

        let config_3 = IITConfig::new(2).with_phi_version(PhiVersion::Phi3_0);
        let iit_3 = QuantumIIT::new(config_3);
        let phi_3 = iit_3.compute_phi(&state);

        let config_star = IITConfig::new(2).with_phi_version(PhiVersion::PhiStar);
        let iit_star = QuantumIIT::new(config_star);
        let phi_star = iit_star.compute_phi(&state);

        // Both should be positive for the Bell state
        assert!(phi_3.phi > 0.0, "Phi 3.0 should be positive for Bell state");
        assert!(
            phi_star.phi > 0.0,
            "Phi* should be positive for Bell state"
        );

        // Both should agree on product state being zero
        let product = product_state_2q();
        let phi_3_prod = iit_3.compute_phi(&product);
        let phi_star_prod = iit_star.compute_phi(&product);

        assert!(phi_3_prod.phi < 1e-6, "Phi 3.0 should be ~0 for product state");
        assert!(phi_star_prod.phi < 1e-6, "Phi* should be ~0 for product state");
    }

    // ----------------------------------------------------------
    // 15. Cause-effect structure has concepts for entangled state
    // ----------------------------------------------------------
    #[test]
    fn test_cause_effect_structure() {
        let state = bell_state();
        let config = IITConfig::new(2);
        let iit = QuantumIIT::new(config);

        let ces = iit.cause_effect_structure(&state);
        assert!(
            ces.num_concepts > 0,
            "Bell state should have at least one concept, got {}",
            ces.num_concepts
        );
        assert!(
            ces.phi > 0.0,
            "CES phi should be positive for Bell state, got {}",
            ces.phi
        );

        // Verify concept structure
        for concept in &ces.concepts {
            assert!(
                !concept.mechanism.is_empty(),
                "Concept mechanism should not be empty"
            );
            assert!(
                concept.phi > 0.0,
                "Concept phi should be positive"
            );
            assert!(
                !concept.cause_repertoire.is_empty(),
                "Cause repertoire should not be empty"
            );
            assert!(
                !concept.effect_repertoire.is_empty(),
                "Effect repertoire should not be empty"
            );
        }

        // Product state should have zero or near-zero concepts
        let product = product_state_2q();
        let ces_prod = iit.cause_effect_structure(&product);
        assert!(
            ces_prod.phi < 1e-6,
            "Product state CES phi should be ~0, got {}",
            ces_prod.phi
        );
    }

