    // ----------------------------------------------------------
    // Extra: Partition validity
    // ----------------------------------------------------------
    #[test]
    fn test_partition_validity() {
        let p = Partition::from_bitmask(4, 0b0101); // {0,2} | {1,3}
        assert!(p.is_valid(4));
        assert_eq!(p.parts[0], vec![0, 2]);
        assert_eq!(p.parts[1], vec![1, 3]);
        assert_eq!(p.total_qubits(), 4);

        let atomic = Partition::atomic(3);
        assert!(atomic.is_valid(3));
        assert_eq!(atomic.parts.len(), 3);
    }

    // ----------------------------------------------------------
    // Extra: Hermitian eigenvalue solver correctness
    // ----------------------------------------------------------
    #[test]
    fn test_hermitian_eigenvalues_identity() {
        // 2x2 identity matrix: eigenvalues should be {1, 1}
        let id = vec![
            C64::new(1.0, 0.0),
            C64::new(0.0, 0.0),
            C64::new(0.0, 0.0),
            C64::new(1.0, 0.0),
        ];
        let eigs = hermitian_eigenvalues(&id, 2);
        assert_eq!(eigs.len(), 2);
        for &e in &eigs {
            assert!(
                (e - 1.0).abs() < 1e-10,
                "Identity eigenvalue should be 1, got {}",
                e
            );
        }
    }

    #[test]
    fn test_hermitian_eigenvalues_pauli_z() {
        // Pauli Z: diag(1, -1)
        let z = vec![
            C64::new(1.0, 0.0),
            C64::new(0.0, 0.0),
            C64::new(0.0, 0.0),
            C64::new(-1.0, 0.0),
        ];
        let eigs = hermitian_eigenvalues(&z, 2);
        assert!((eigs[0] - 1.0).abs() < 1e-10);
        assert!((eigs[1] - (-1.0)).abs() < 1e-10);
    }

    #[test]
    fn test_hermitian_eigenvalues_pauli_x() {
        // Pauli X: [[0,1],[1,0]], eigenvalues +1, -1
        let x = vec![
            C64::new(0.0, 0.0),
            C64::new(1.0, 0.0),
            C64::new(1.0, 0.0),
            C64::new(0.0, 0.0),
        ];
        let eigs = hermitian_eigenvalues(&x, 2);
        assert!((eigs[0] - 1.0).abs() < 1e-10, "Pauli X eigenvalue 0: {}", eigs[0]);
        assert!((eigs[1] - (-1.0)).abs() < 1e-10, "Pauli X eigenvalue 1: {}", eigs[1]);
    }

    // ----------------------------------------------------------
    // Extra: Phi 2.0 from TPM
    // ----------------------------------------------------------
    #[test]
    fn test_phi_2_0_from_tpm() {
        let config = IITConfig::new(2).with_phi_version(PhiVersion::Phi2_0);
        let iit = QuantumIIT::new(config);

        // Build a simple 2-qubit Hadamard + CNOT unitary
        let h = 1.0 / 2.0_f64.sqrt();
        // H tensor I, then CNOT
        let mut state = QuantumState::new(2);
        GateOperations::h(&mut state, 0);
        GateOperations::cnot(&mut state, 0, 1);

        let result = iit.compute_phi(&state);
        // Just verify it runs and returns reasonable values
        assert!(result.phi >= 0.0, "Phi 2.0 should be non-negative");
        assert!(result.num_partitions_tested > 0);
    }

