    // ----------------------------------------------------------
    // Extra: TPM from quantum channel
    // ----------------------------------------------------------
    #[test]
    fn test_tpm_from_quantum_channel() {
        // Identity channel: single Kraus op = I
        let kraus_i = vec![
            vec![C64::new(1.0, 0.0), C64::new(0.0, 0.0)],
            vec![C64::new(0.0, 0.0), C64::new(1.0, 0.0)],
        ];
        let channel = vec![kraus_i];
        let tpm = TransitionProbabilityMatrix::from_quantum_channel(&channel);

        assert!(tpm.is_stochastic(1e-10));
        // Identity channel: TPM should be identity
        assert!((tpm.matrix[0][0] - 1.0).abs() < 1e-10);
        assert!((tpm.matrix[0][1]).abs() < 1e-10);
        assert!((tpm.matrix[1][0]).abs() < 1e-10);
        assert!((tpm.matrix[1][1] - 1.0).abs() < 1e-10);
    }

