    // ----------------------------------------------------------
    // Extra: 3-qubit partial trace consistency
    // ----------------------------------------------------------
    #[test]
    fn test_partial_trace_3q() {
        let state = ghz_state_3q();
        let amps = state.amplitudes_ref();
        let rho = density_matrix_from_state(amps);
        let n = 3;

        // Trace out qubit 2, keep {0, 1}
        let rho_01 = partial_trace(&rho, n, &[0, 1]);
        let tr_01 = matrix_trace(&rho_01, 4);
        assert!(
            (tr_01.re - 1.0).abs() < 1e-10,
            "Tr(rho_01) should be 1, got {}",
            tr_01.re
        );

        // For GHZ: rho_{01} = (|00><00| + |11><11|) / 2
        assert!(
            (rho_01[0].re - 0.5).abs() < 1e-10,
            "GHZ rho_01[0][0] should be 0.5"
        );
        assert!(
            (rho_01[15].re - 0.5).abs() < 1e-10,
            "GHZ rho_01[3][3] should be 0.5"
        );

        // Single-qubit reduced state of GHZ should also be maximally mixed
        let rho_0 = partial_trace(&rho, n, &[0]);
        assert!((rho_0[0].re - 0.5).abs() < 1e-10);
        assert!((rho_0[3].re - 0.5).abs() < 1e-10);
    }

